    pub const fn summon_aery(ctx: &Ctx) -> f32 {
        (10.0 + 40.0 / 17.0 * (ctx.level - 1.0) + 0.1 * ctx.bonus_ad + 0.05 * ctx.ability_power)
            * ctx.adaptive_damage
    }
